#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[200005];
        scanf("%s", s);
        int n = strlen(s);
        long long ans;
        if (s[0] == s[n-1]) {
            ans = n - 2;
            if (ans < 0) ans = 0;
        } else {
            ans = 2;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

