#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        s = data[idx]; idx += 1
        n = len(s)
        if s[0] == s[-1]:
            ans = n - 2
            if ans < 0:
                ans = 0
        else:
            ans = 2
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

